  float I = 0; // Intensity
  float Ae, Am; // Albedo (reflection coefficient) for electrons and ions
  float Be, Bm; // Refraction index for electrons and ions
  float ne, nm; // Electron and ion densities
  float ve, vm; // Electron and ion velocities

  // Calculate electron and ion densities and velocities
  ne = density * electrons_per_molecul;
  nm = density * ions_per_molecule;
  ve = velocity * electrons_per_molecule;
  vm = velocity * ions_per_molecule;

